args.sparql:
SELECT (COUNT(?country) + 1 AS ?rank) WHERE {
  wd:Q103 wdt:P2550 ?india_rate.
  ?country wdt:P2550 ?other_rate.
  ?country wdt:P31 wd:Q6256.
  FILTER(?other_rate > ?india_rate)
}

SELECT (COUNT(?country) + 1 AS ?rank) WHERE {
  wd:Q103 wdt:P2051 ?india_rate.
  ?country wdt:P2051 ?country_rate.
  ?country wdt:P31 wd:Q6256.
  FILTER(?country_rate > ?india_rate)
}

SELECT (COUNT(?country) + 1 AS ?rank) WHERE {
  wd:Q103 wdt:P2550 ?india_rate.
  ?country wdt:P2550 ?country_rate.
  ?country wdt:P31 wd:Q6256.
  FILTER(?country_rate > ?india_rate)
}
